document.addEventListener("DOMContentLoaded",function(){const a=document.getElementById("toc-background-mask"),b=document.getElementById("toc-container"),c=document.querySelectorAll("#toc-button, #toc-background-mask, #toc-list a");c.forEach(c=>{c.addEventListener("click",c=>{c.stopPropagation(),a.classList.contains("active")?(b.classList.add("translate-x-full"),setTimeout(function(){a.style.visibility=""},300)):(a.style.visibility="visible",b.classList.remove("translate-x-full")),a.classList.toggle("active")})})})